#!/usr/bin/env bash
# lifecycle: permanent
# M3-D4D-B1 local-only persistent sandbox operator. It never reads project .env.
set -euo pipefail

ROOT="$(cd "$(dirname "${BASH_SOURCE[0]}")/../../.." && pwd)"
PROJECT="fp_m3_persistent_sandbox"; SERVICE="m3-persistent-postgres"; DATABASE="fp_m3_persistent_sandbox"
COMPOSE_FILE="$ROOT/deploy/sandbox/m3_odds_staging/docker-compose.yml"
SECRET_DIR="${HOME}/.config/footballprediction/m3-persistent-sandbox"; BACKUP_DIR="${HOME}/.local/share/footballprediction/backups/m3-persistent-sandbox"
ENV_FILE="$SECRET_DIR/compose.env"; RUNTIME_ENV_FILE="$SECRET_DIR/runtime.env"; PGPASS_FILE="$SECRET_DIR/pgpass"; LOCK_KEY="731642941"
MIGRATIONS=("V26.8__create_odds_historical_staging_contract.sql" "V26.9__add_odds_historical_observation_fingerprint.sql")
die() { echo "BLOCKED: $*" >&2; exit 1; }
require_tool() { command -v "$1" >/dev/null || die "required command missing: $1"; }
compose() { docker compose --env-file "$ENV_FILE" -p "$PROJECT" -f "$COMPOSE_FILE" "$@"; }
safe_identity() { [[ "$PROJECT" == fp_m3_persistent_sandbox && "$SERVICE" == m3-persistent-postgres && "$DATABASE" == fp_m3_persistent_sandbox ]] || die "fixed sandbox identity mismatch"; }
ensure_secret_files() {
  if [[ -e "$SECRET_DIR" && ! -d "$SECRET_DIR" ]]; then die "secret path is not a directory"; fi
  mkdir -p "$SECRET_DIR" "$BACKUP_DIR"; chmod 700 "$SECRET_DIR" "$BACKUP_DIR"
  if [[ -e "$ENV_FILE" || -e "$RUNTIME_ENV_FILE" || -e "$PGPASS_FILE" ]]; then
    [[ -f "$ENV_FILE" && -f "$RUNTIME_ENV_FILE" && -f "$PGPASS_FILE" ]] || die "incomplete existing secret material; refusing overwrite"
    [[ "$(stat -c '%a' "$SECRET_DIR")" == 700 && "$(stat -c '%a' "$ENV_FILE")" == 600 && "$(stat -c '%a' "$RUNTIME_ENV_FILE")" == 600 && "$(stat -c '%a' "$PGPASS_FILE")" == 600 ]] || die "existing secret permissions are unsafe"; return
  fi
  umask 077; local owner migrator writer reader
  owner="$(openssl rand -hex 32)"; migrator="$(openssl rand -hex 32)"; writer="$(openssl rand -hex 32)"; reader="$(openssl rand -hex 32)"
  printf 'M3_SANDBOX_DATABASE=%s\nM3_SANDBOX_OWNER_USER=%s\nM3_SANDBOX_OWNER_PASSWORD=%s\nM3_SANDBOX_SECRET_DIR=%s\nM3_SANDBOX_BACKUP_DIR=%s\nM3_SANDBOX_RUNTIME_ENV_FILE=%s\n' "$DATABASE" fp_m3_sandbox_owner "$owner" "$SECRET_DIR" "$BACKUP_DIR" "$RUNTIME_ENV_FILE" > "$ENV_FILE"
  printf 'M3_SANDBOX_MIGRATOR_PASSWORD=%s\nM3_SANDBOX_WRITER_PASSWORD=%s\nM3_SANDBOX_READER_PASSWORD=%s\n' "$migrator" "$writer" "$reader" > "$RUNTIME_ENV_FILE"
  printf '%s:%s:%s:%s:%s\n%s:%s:%s:%s:%s\n%s:%s:%s:%s:%s\n%s:%s:%s:%s:%s\n' "$SERVICE" 5432 "$DATABASE" fp_m3_sandbox_owner "$owner" "$SERVICE" 5432 "$DATABASE" fp_m3_sandbox_migrator "$migrator" "$SERVICE" 5432 "$DATABASE" fp_m3_sandbox_writer "$writer" "$SERVICE" 5432 "$DATABASE" fp_m3_sandbox_reader "$reader" > "$PGPASS_FILE"; chmod 600 "$ENV_FILE" "$RUNTIME_ENV_FILE" "$PGPASS_FILE"
}
operator_psql() { compose --profile operator run --rm -T --entrypoint psql m3-persistent-operator -X -v ON_ERROR_STOP=1 "$@"; }
owner_psql() { operator_psql -U fp_m3_sandbox_owner "$@"; }
ensure_running() { compose up -d "$SERVICE" >/dev/null; compose ps --status running "$SERVICE" | grep -q "$SERVICE" || die "sandbox service did not start"; }
bootstrap() { safe_identity; require_tool docker; require_tool openssl; ensure_secret_files; ensure_running; owner_psql -f /sandbox-bootstrap/bootstrap_roles.sql; echo "BOOTSTRAPPED project=$PROJECT service=$SERVICE database=$DATABASE postgres=15 host-port=none"; }
ledger_row() { owner_psql -At -c "SELECT sha256_checksum FROM odds_staging_schema_migrations WHERE version='$1'"; }
plan() { safe_identity; [[ -f "$ENV_FILE" ]] || die "run bootstrap first"; ensure_running; for file in "${MIGRATIONS[@]}"; do local version checksum recorded; version="${file%%__*}"; checksum="$(sha256sum "$ROOT/database/migrations/$file" | awk '{print $1}')"; recorded="$(ledger_row "$version")"; if [[ -z "$recorded" ]]; then echo "$version $file $checksum pending"; elif [[ "$recorded" == "$checksum" ]]; then echo "$version $file $checksum already-applied"; else die "checksum-conflict for $version"; fi; done; }
authorize_apply() { [[ "${ALLOW_M3_PERSISTENT_SANDBOX_MIGRATION:-}" == 1 && "${M3_D4D_B1_SANDBOX_MIGRATION_CONFIRMATION:-}" == I_AUTHORIZE_M3_D4D_B1_SANDBOX_MIGRATION ]] || die "explicit sandbox migration authorization required"; }
apply() { safe_identity; authorize_apply; bootstrap; plan; for file in "${MIGRATIONS[@]}"; do local version checksum; version="${file%%__*}"; [[ -z "$(ledger_row "$version")" ]] || continue; checksum="$(sha256sum "$ROOT/database/migrations/$file" | awk '{print $1}')"; compose --profile operator run --rm -T --entrypoint sh m3-persistent-operator -lc "psql -X -v ON_ERROR_STOP=1 -U fp_m3_sandbox_owner -v version='$version' -v filename='$file' -v checksum='$checksum' <<'SQL'
SELECT pg_try_advisory_lock($LOCK_KEY) AS lock_acquired \\gset
\\if :lock_acquired
BEGIN;
SET ROLE fp_m3_sandbox_migrator;
\\i /migrations/$file
INSERT INTO odds_staging_schema_migrations (version,filename,sha256_checksum,applied_by,execution_duration_ms) VALUES (:'version',:'filename',:'checksum',current_user,0);
COMMIT;
SELECT pg_advisory_unlock($LOCK_KEY);
\\else
\\quit
\\endif
SQL" || die "migration $version failed; transaction rolled back"; done; owner_psql -f /sandbox-bootstrap/finalize_staging_grants.sql; status; }
status() { safe_identity; ensure_running; owner_psql -c "SELECT version,filename,sha256_checksum,applied_by FROM odds_staging_schema_migrations ORDER BY version"; owner_psql -c "SELECT 'odds_historical_import_runs' table_name,count(*) row_count FROM odds_historical_import_runs UNION ALL SELECT 'odds_historical_source_files',count(*) FROM odds_historical_source_files UNION ALL SELECT 'odds_historical_staging_observations',count(*) FROM odds_historical_staging_observations UNION ALL SELECT 'odds_historical_quarantine',count(*) FROM odds_historical_quarantine"; }
verify() { safe_identity; status; owner_psql -At -c "SELECT count(*) FROM odds_historical_staging_observations WHERE business_fingerprint IS NULL" | grep -qx 0 || die "NULL fingerprint inventory is nonzero"; owner_psql -At -c "SELECT has_table_privilege('fp_m3_sandbox_writer','odds_historical_quarantine','insert') AND NOT has_table_privilege('fp_m3_sandbox_writer','odds_historical_quarantine','delete') AND NOT has_table_privilege('fp_m3_sandbox_reader','odds_historical_quarantine','select')" | grep -qx t || die "role matrix verification failed"; echo "VERIFIED empty-business-inventory=true candidate-identity=not_proven matches-fk=absent"; }
backup() { safe_identity; verify; mkdir -p "$BACKUP_DIR"; chmod 700 "$BACKUP_DIR"; local stamp file operator_id; stamp="$(date -u +%Y%m%dT%H%M%SZ)"; file="$BACKUP_DIR/m3-persistent-sandbox-$stamp.dump"; compose --profile operator create m3-persistent-operator >/dev/null; operator_id="$(compose --profile operator ps -aq m3-persistent-operator)"; [[ -n "$operator_id" ]] || die "sandbox backup operator was not created"; docker start "$operator_id" >/dev/null; docker exec "$operator_id" pg_dump -U fp_m3_sandbox_owner -Fc -f /tmp/m3-sandbox-backup.dump; docker cp "$operator_id:/tmp/m3-sandbox-backup.dump" "$file"; docker rm -f "$operator_id" >/dev/null; [[ -s "$file" ]] || die "backup extraction failed"; chmod 600 "$file"; sha256sum "$file" > "$file.sha256"; chmod 600 "$file.sha256"; echo "BACKUP file=$(basename "$file") sha256=$(awk '{print $1}' "$file.sha256")"; }
stop() { [[ -f "$ENV_FILE" ]] || die "sandbox is not initialized"; compose down --remove-orphans; }
restore_verify() {
  safe_identity; require_tool docker; require_tool openssl
  local backup="${M3_SANDBOX_RESTORE_BACKUP:-}" checksum nonce project db name net dir inv positive role_attributes memberships
  [[ -n "$backup" ]] || die "M3_SANDBOX_RESTORE_BACKUP must name the exact repo-external backup to restore"
  [[ "$backup" == "$BACKUP_DIR"/* && "$backup" == *.dump ]] || die "restore backup must be an exact .dump inside the sandbox backup directory"
  checksum="${backup}.sha256"
  [[ -f "$backup" && -f "$checksum" && "$(sha256sum "$backup" | awk '{print $1}')" == "$(awk '{print $1}' "$checksum")" ]] || die "backup checksum mismatch"
  nonce="$(date -u +%s)_$RANDOM"; project="fp_m3_restore_verify_$nonce"; db="fp_m3_restore_verify_$nonce"; name="${project}-m3-restore-postgres-1"; net="${project}_default"; dir="$(mktemp -d /tmp/m3-restore.XXXXXX)"; chmod 700 "$dir"
  cleanup_restore() { docker rm -f "$name" >/dev/null 2>&1 || true; docker network rm "$net" >/dev/null 2>&1 || true; rm -rf "$dir"; }
  trap cleanup_restore EXIT INT TERM
  umask 077; printf 'POSTGRES_DB=%s\nPOSTGRES_USER=fp_m3_sandbox_owner\nPOSTGRES_PASSWORD=%s\n' "$db" "$(openssl rand -hex 32)" > "$dir/env"; chmod 600 "$dir/env"
  docker network create --label com.footballprediction.scope=m3-d4d-b1-restore-verify --label com.footballprediction.production=false "$net" >/dev/null
  docker run -d --name "$name" --network "$net" --tmpfs /var/lib/postgresql/data:rw,noexec,nosuid,size=256m --env-file "$dir/env" --label com.footballprediction.scope=m3-d4d-b1-restore-verify --label com.footballprediction.production=false postgres:15-alpine >/dev/null
  for _ in $(seq 1 30); do docker exec "$name" sh -lc 'PGPASSWORD="$POSTGRES_PASSWORD" pg_isready -U "$POSTGRES_USER" -d "$POSTGRES_DB"' >/dev/null 2>&1 && break; sleep 1; done
  docker exec "$name" sh -lc 'PGPASSWORD="$POSTGRES_PASSWORD" pg_isready -U "$POSTGRES_USER" -d "$POSTGRES_DB"' >/dev/null || die "clone unavailable"
  docker exec -i "$name" sh -lc 'PGPASSWORD="$POSTGRES_PASSWORD" psql -X -v ON_ERROR_STOP=1 -U "$POSTGRES_USER" -d "$POSTGRES_DB"' <<'SQL'
\getenv p POSTGRES_PASSWORD
SELECT format('CREATE ROLE fp_m3_sandbox_migrator NOLOGIN NOINHERIT; CREATE ROLE fp_m3_sandbox_writer LOGIN NOINHERIT PASSWORD %L; CREATE ROLE fp_m3_sandbox_reader LOGIN NOINHERIT PASSWORD %L;', :'p', :'p') \gexec
SELECT format('REVOKE ALL PRIVILEGES ON DATABASE %I FROM PUBLIC', current_database()) \gexec
SELECT format('GRANT CONNECT ON DATABASE %I TO fp_m3_sandbox_migrator,fp_m3_sandbox_writer,fp_m3_sandbox_reader', current_database()) \gexec
