SQL
  docker cp "$backup" "$name:/tmp/backup.dump"; docker exec "$name" sh -lc 'PGPASSWORD="$POSTGRES_PASSWORD" pg_restore -U "$POSTGRES_USER" -d "$POSTGRES_DB" --exit-on-error /tmp/backup.dump' >/dev/null
  docker cp "$ROOT/database/sandbox/m3_odds_staging/finalize_staging_grants.sql" "$name:/tmp/finalize.sql"; docker exec "$name" sh -lc 'PGPASSWORD="$POSTGRES_PASSWORD" psql -X -v ON_ERROR_STOP=1 -U "$POSTGRES_USER" -d "$POSTGRES_DB" -f /tmp/finalize.sql' >/dev/null
  owner_sql() { docker exec -i "$name" sh -lc 'PGPASSWORD="$POSTGRES_PASSWORD" psql -X -v ON_ERROR_STOP=1 -U "$POSTGRES_USER" -d "$POSTGRES_DB" "$@"' sh "$@"; }
  role_sql() { local role="$1"; shift; docker exec -i "$name" sh -lc 'role="$1"; shift; PGPASSWORD="$POSTGRES_PASSWORD" psql -X -v ON_ERROR_STOP=1 -U "$role" -d "$POSTGRES_DB" "$@"' sh "$role" "$@"; }
  scalar() { printf '%s\n' "$1" | owner_sql -At; }
  denial() { local role="$1" probe="$2" command="$3" catalog="$4" before after out rc; before="$(scalar "$catalog")"; set +e; out="$(printf '\\set VERBOSITY verbose\n%s\n' "$command" | role_sql "$role" 2>&1)"; rc=$?; set -e; after="$(scalar "$catalog")"; [[ $rc -ne 0 && "$out" == *42501* && "$before" == "$after" ]] || die "denial failed probe=$probe exit=$rc catalog_before=$before catalog_after=$after stderr=${out//$'\n'/ }"; echo "PROBE name=$probe role=$role exit=$rc sqlstate=42501 expected=42501 result=PASS catalog_delta=0 sanitized_stderr=permission_denied"; }
  [[ "$(scalar "SELECT count(*) FROM information_schema.columns WHERE table_schema=current_schema() AND table_name IN ('odds_historical_import_runs','odds_historical_source_files','odds_historical_staging_observations','odds_historical_quarantine')")" -gt 0 ]] || die "column inventory missing"
  [[ "$(scalar "SELECT count(*) FROM pg_constraint WHERE conrelid IN ('odds_historical_import_runs'::regclass,'odds_historical_source_files'::regclass,'odds_historical_staging_observations'::regclass,'odds_historical_quarantine'::regclass)")" -gt 0 ]] || die "constraint inventory missing"
  [[ "$(scalar "SELECT count(*) FROM pg_indexes WHERE schemaname=current_schema() AND tablename IN ('odds_historical_import_runs','odds_historical_source_files','odds_historical_staging_observations','odds_historical_quarantine')")" -ge 9 ]] || die "index inventory missing"
  [[ "$(scalar "SELECT count(*) FROM odds_staging_schema_migrations WHERE (version='V26.8' AND sha256_checksum='$(sha256sum "$ROOT/database/migrations/V26.8__create_odds_historical_staging_contract.sql" | awk '{print $1}')') OR (version='V26.9' AND sha256_checksum='$(sha256sum "$ROOT/database/migrations/V26.9__add_odds_historical_observation_fingerprint.sql" | awk '{print $1}')')")" == 2 ]] || die "migration ledger/checksum verification failed"
  positive="$(role_sql fp_m3_sandbox_writer -At <<'SQL'
