INSERT INTO odds_historical_import_runs (id,run_key,source_type,mode,status,pipeline_version,expected_accepted_count,expected_quarantine_count,metadata) VALUES ('aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa',repeat('a',64),'historical_odds','controlled_write','planned','restore-role-probe',1,1,'{"probe":true}'::jsonb);
