)"; [[ "$positive" == *"1|1|1|1|1|1"* && "$positive" == *ROLLBACK* ]] || die "writer positive probe failed output=${positive//$'\n'/ }"; echo "PROBE name=writer_positive role=fp_m3_sandbox_writer result=PASS rows_inside_transaction=1,1,1,1 rollback=true"
  denial fp_m3_sandbox_writer create_role 'CREATE ROLE writer_forbidden_role_probe' "SELECT count(*) FROM pg_roles WHERE rolname='writer_forbidden_role_probe'"
  denial fp_m3_sandbox_writer create_database 'CREATE DATABASE writer_forbidden_database_probe' "SELECT count(*) FROM pg_database WHERE datname='writer_forbidden_database_probe'"
