  printf '%s\n' 'SELECT count(*) FROM odds_historical_staging_observations; SELECT count(*) FROM odds_historical_import_runs; SELECT count(*) FROM odds_historical_source_files;' | role_sql fp_m3_sandbox_reader >/dev/null; echo "PROBE name=reader_allowed_select role=fp_m3_sandbox_reader result=PASS"
