  [[ "$(scalar "SELECT count(*) FROM pg_auth_members WHERE member IN ('fp_m3_sandbox_writer'::regrole,'fp_m3_sandbox_reader'::regrole) AND roleid IN ('fp_m3_sandbox_owner'::regrole,'fp_m3_sandbox_migrator'::regrole,'fp_m3_sandbox_writer'::regrole)")" == 0 ]] || die "dangerous membership found"; [[ "$(scalar "SELECT count(*) FROM pg_roles WHERE rolname IN ('fp_m3_sandbox_writer','fp_m3_sandbox_reader') AND (rolsuper OR rolcreaterole OR rolcreatedb OR rolbypassrls)")" == 0 ]] || die "unsafe writer/reader role attributes"; [[ "$(scalar "SELECT count(*) FROM pg_namespace n CROSS JOIN LATERAL aclexplode(n.nspacl) a WHERE n.nspname='public' AND a.grantee=0 AND a.privilege_type='CREATE'")" == 0 && "$(scalar "SELECT count(*) FROM pg_roles r WHERE r.rolname IN ('fp_m3_sandbox_writer','fp_m3_sandbox_reader') AND has_schema_privilege(r.oid,'public','CREATE')")" == 0 ]] || die "schema CREATE exposure found"; [[ "$(scalar "SELECT count(*) FROM pg_class c CROSS JOIN LATERAL aclexplode(c.relacl) a WHERE c.relname IN ('odds_historical_import_runs','odds_historical_source_files','odds_historical_staging_observations','odds_historical_quarantine') AND a.grantee=0 AND a.privilege_type IN ('SELECT','INSERT','UPDATE','DELETE','TRUNCATE','REFERENCES','TRIGGER')")" == 0 ]] || die "PUBLIC table privilege exposure found"; [[ "$(scalar "SELECT count(*) FROM pg_class c JOIN pg_namespace n ON n.oid=c.relnamespace CROSS JOIN LATERAL aclexplode(c.relacl) a WHERE n.nspname=current_schema() AND c.relkind='S' AND a.grantee=0 AND a.privilege_type IN ('USAGE','SELECT','UPDATE')")" == 0 ]] || die "PUBLIC sequence privilege exposure found"; [[ "$(scalar "SELECT count(*) FROM pg_class c JOIN pg_namespace n ON n.oid=c.relnamespace WHERE n.nspname=current_schema() AND c.relkind='S' AND (NOT has_sequence_privilege('fp_m3_sandbox_writer',c.oid,'USAGE') OR has_sequence_privilege('fp_m3_sandbox_writer',c.oid,'SELECT') OR has_sequence_privilege('fp_m3_sandbox_writer',c.oid,'UPDATE') OR has_sequence_privilege('fp_m3_sandbox_reader',c.oid,'USAGE') OR has_sequence_privilege('fp_m3_sandbox_reader',c.oid,'UPDATE'))")" == 0 ]] || die "sequence least-privilege verification failed"; [[ "$(scalar "SELECT count(*) FROM pg_proc p JOIN pg_namespace n ON n.oid=p.pronamespace CROSS JOIN LATERAL aclexplode(p.proacl) a WHERE n.nspname=current_schema() AND a.grantee=0 AND a.privilege_type='EXECUTE'")" == 0 ]] || die "PUBLIC function execute exposure found"; [[ "$(scalar "SELECT count(*) FROM pg_default_acl d JOIN pg_roles r ON r.oid=d.defaclrole CROSS JOIN LATERAL aclexplode(d.defaclacl) a WHERE r.rolname IN ('fp_m3_sandbox_owner','fp_m3_sandbox_migrator') AND a.grantee IN (0,'fp_m3_sandbox_writer'::regrole,'fp_m3_sandbox_reader'::regrole)")" == 0 ]] || die "unsafe default privilege exposure found"
  role_attributes="$(scalar "SELECT string_agg(rolname||':super='||rolsuper||',inherit='||rolinherit||',createrole='||rolcreaterole||',createdb='||rolcreatedb||',login='||rolcanlogin||',replication='||rolreplication||',bypassrls='||rolbypassrls, ';' ORDER BY rolname) FROM pg_roles WHERE rolname IN ('fp_m3_sandbox_owner','fp_m3_sandbox_migrator','fp_m3_sandbox_writer','fp_m3_sandbox_reader')")"; memberships="$(scalar "SELECT coalesce(string_agg(member::regrole::text||'->'||roleid::regrole::text, ';' ORDER BY 1),'none') FROM pg_auth_members WHERE member IN ('fp_m3_sandbox_owner'::regrole,'fp_m3_sandbox_migrator'::regrole,'fp_m3_sandbox_writer'::regrole,'fp_m3_sandbox_reader'::regrole) OR roleid IN ('fp_m3_sandbox_owner'::regrole,'fp_m3_sandbox_migrator'::regrole,'fp_m3_sandbox_writer'::regrole,'fp_m3_sandbox_reader'::regrole)")"; echo "ROLE_AUDIT $role_attributes"; echo "MEMBERSHIP_AUDIT $memberships"; echo "AUDIT roles=passed memberships=passed public_database_create=$(scalar "SELECT count(*) FROM pg_database d CROSS JOIN LATERAL aclexplode(d.datacl) a WHERE d.datname=current_database() AND a.grantee=0 AND a.privilege_type='CREATE'") public_schema_create=false public_table_dml=false public_sequence_privileges=false functions_in_schema=$(scalar "SELECT count(*) FROM pg_proc p JOIN pg_namespace n ON n.oid=p.pronamespace WHERE n.nspname=current_schema()") default_acl_rows=$(scalar "SELECT count(*) FROM pg_default_acl WHERE defaclrole IN ('fp_m3_sandbox_owner'::regrole,'fp_m3_sandbox_migrator'::regrole)")"
  inv="$(scalar "SELECT (SELECT count(*) FROM odds_staging_schema_migrations),(SELECT count(*) FROM odds_historical_import_runs),(SELECT count(*) FROM odds_historical_source_files),(SELECT count(*) FROM odds_historical_staging_observations),(SELECT count(*) FROM odds_historical_quarantine),(SELECT count(*) FROM odds_historical_staging_observations WHERE business_fingerprint IS NULL),(SELECT count(*) FROM pg_roles WHERE rolname='writer_forbidden_role_probe'),(SELECT count(*) FROM pg_database WHERE datname='writer_forbidden_database_probe')")"; [[ "$inv" == '2|0|0|0|0|0|0|0' ]] || die "nonzero clone inventory: $inv"
  echo "RESTORE_VERIFY project=$project service=m3-restore-postgres database=$db postgres=15 storage=tmpfs host_ports=none pg_restore=0 ledger=2 rows=0 backup=$(basename "$backup")"; cleanup_restore; trap - EXIT INT TERM
}
# Production wrapper remains fixed to V26.8/V26.9 and has no custom-directory or pause input.
apply() {
  safe_identity; authorize_apply; bootstrap; plan
  local file version container checksum core
  container="$(compose ps -q "$SERVICE")"; [[ -n "$container" ]] || die "sandbox container unavailable"
  core="$ROOT/scripts/ops/odds_staging/m3_migration_runner_core.sh"
  for file in "${MIGRATIONS[@]}"; do
    version="${file%%__*}"; [[ -z "$(ledger_row "$version")" ]] || continue
    checksum="$(sha256sum "$ROOT/database/migrations/$file" | awk '{print $1}')"
    bash "$core" --container "$container" --database "$DATABASE" --file "$ROOT/database/migrations/$file" --checksum "$checksum" --pause-seconds 0 || die "migration $version failed; transaction rolled back"
  done
  owner_psql -f /sandbox-bootstrap/finalize_staging_grants.sql; status
}
case "${1:-}" in
  bootstrap|plan|status|verify|backup|stop) "$1" ;;
  restore_verify) restore_verify ;;
  migrate) apply ;;
  *) echo "usage: $0 {bootstrap|plan|migrate|status|verify|backup|restore_verify|stop}" >&2; exit 2 ;;
esac
